function formatFileSize(sizeInBytes) {
    if (sizeInBytes < 1024) {
        return `${sizeInBytes} B`;
    }
    const units = [
        'KB',
        'MB',
        'GB'
    ];
    let size = sizeInBytes / 1024;
    let unitIndex = 0;
    while(size >= 1024 && unitIndex < units.length - 1){
        size /= 1024;
        unitIndex += 1;
    }
    return `${size.toFixed(size >= 10 || unitIndex > 0 ? 1 : 2)} ${units[unitIndex]}`;
}
